mapper.select:
SELECT id, code, title, skill, level, topic, exam_type, script_text, storage_key, source, folder, created_at
FROM dictation_clips
WHERE id = #{clipId}

mapper.update:
UPDATE dictation_clip_sentences
SET start_ms = #{startMs}, end_ms = #{endMs}
WHERE clip_id = #{clipId} AND seq = #{seq}

UPDATE dictation_clip_sentences
SET translation = #{translation}
WHERE clip_id = #{clipId} AND seq = #{seq}

mapper.select:
SELECT lower(expected_word) AS word, count(*) AS miss_count
FROM dictation_misses
WHERE user_id = #{userId}
GROUP BY lower(expected_word)
ORDER BY miss_count DESC, word ASC
LIMIT #{limit}

SELECT id, user_id, sentence_text, source, storage_key, level, exam_type, topic, translation_text, created_at
FROM dictation_practice_items
WHERE id = #{practiceItemId}
